CREATE OR REPLACE FUNCTION OFSERM.SEC_RWA_EXP_STD_ACCT_HEAD_DATA_POP_IRB(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_EXP_STD_ACCT_HEAD(N_MIS_DATE_SKEY,N_RUN_SKEY,N_CAP_APPROACH_TYPE_SKEY,N_CAP_COMP_GROUP_SKEY,N_CAP_RECORD_TYPE_SKEY,N_GAAP_SKEY,N_STD_ACCT_HEAD_AMT,N_STD_ACCT_HEAD_SKEY,V_RECORD_TYPE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_RUN.N_RUN_SKEY),'-1',DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY,'-1',SEC_IRB.N_GAAP_SKEY,SUM(COALESCE(SEC_IRB.N_STD_ACCT_HEAD_AMT,0)),SEC_IRB.N_STD_ACCT_HEAD_SKEY,SEC_IRB.V_RECORD_TYPE FROM (SELECT n_mis_date_skey,N_RUN_SKEY,V_RECORD_TYPE,N_GAAP_SKEY,SUM(N_STD_ACCT_HEAD_AMT) N_STD_ACCT_HEAD_AMT,N_STD_ACCT_HEAD_SKEY,MAX(V_CCY_CODE) V_CCY_CODE FROM (/*FOR RWA OF UNDERLYING EXPOSURES WITH IMPLICIT SUPPORT FOR SECURITIZATION-Y/CLEANUP CALL OPTION-N/SYNTHETIC RISK TRANSFER-N/SYNTHETIC RISK TRANSFER-Y AND TRANCHE SECOND LOSS POSITION AND ELIBILE PROTECTION CREDIT DERIVATIVE-Y*/ SELECT FSI_CAP_SEC_UNDERLYING.n_mis_date_skey n_mis_date_skey,FSI_CAP_SEC_UNDERLYING.N_RUN_SKEY N_RUN_SKEY,FSI_CAP_SEC_UNDERLYING.N_GAAP_SKEY N_GAAP_SKEY,SUM(COALESCE(COALESCE(FSI_CAP_SEC_UNDERLYING.n_rwa_ul_amt, FSI_CAP_SEC_UNDERLYING.n_pre_mitigation_rwa_ul), 0)) n_std_acct_head_amt,(SELECT MAX(N_STD_ACCT_HEAD_SKEY) FROM DIM_STANDARD_ACCT_HEAD A WHERE A.V_STD_ACCT_HEAD_ID = 'CAP218' AND to_date('20260331','YYYYMMDD') BETWEEN A.D_RECORD_START_DATE and A.D_RECORD_END_DATE) N_STD_ACCT_HEAD_SKEY,MAX(FSI_CAP_SEC_UNDERLYING.V_CCY_CODE) V_CCY_CODE,FSI_CAP_SEC_UNDERLYING.V_RECORD_TYPE,0 N_BASEL_METHOD_SKEY FROM FSI_CAP_SEC_UNDERLYING LEFT OUTER JOIN FCT_SECURITIZATION_POOL ON FSI_CAP_SEC_UNDERLYING.N_SEC_POOL_SKEY = FCT_SECURITIZATION_POOL.N_SEC_POOL_SKEY AND FSI_CAP_SEC_UNDERLYING.N_RUN_SKEY = FCT_SECURITIZATION_POOL.N_RUN_SKEY AND FSI_CAP_SEC_UNDERLYING.n_mis_date_skey = FCT_SECURITIZATION_POOL.n_mis_date_skey LEFT OUTER JOIN DIM_DATES ON FSI_CAP_SEC_UNDERLYING.n_mis_date_skey = DIM_DATES.n_date_skey WHERE FSI_CAP_SEC_UNDERLYING.N_RUN_SKEY = '870' AND FSI_CAP_SEC_UNDERLYING.n_mis_date_skey = DIM_DATES.n_date_skey AND FSI_CAP_SEC_UNDERLYING.N_STD_ACCT_HEAD_SKEY IS NULL AND COALESCE(FSI_CAP_SEC_UNDERLYING.F_SECURITIZED_FLAG, 'N') = 'Y' AND (COALESCE(FCT_SECURITIZATION_POOL.F_IMPLICIT_SUPPORT_IND, 'N') = 'Y' OR COALESCE(FCT_SECURITIZATION_POOL.F_CLEANUP_CALL_OPTION_IND, 'Y') = 'N' OR COALESCE(FCT_SECURITIZATION_POOL.F_SYNTHETIC_TRANSFER_RSK_IND, 'N') = 'N' OR (COALESCE(FCT_SECURITIZATION_POOL.F_SYNTHETIC_TRANSFER_RSK_IND, 'N') = 'Y' AND COALESCE(FSI_CAP_SEC_UNDERLYING.F_ELIGIBLE_PROTECTION_IND, 'N') = 'Y')) GROUP BY FSI_CAP_SEC_UNDERLYING.n_mis_date_skey,FSI_CAP_SEC_UNDERLYING.N_RUN_SKEY,FSI_CAP_SEC_UNDERLYING.N_GAAP_SKEY,FSI_CAP_SEC_UNDERLYING.V_RECORD_TYPE UNION /*FOR RWA EXCLUDING CLEAN UP CALL*/ SELECT E.n_mis_date_skey n_mis_date_skey,E.N_RUN_SKEY N_RUN_SKEY,E.N_GAAP_SKEY N_GAAP_SKEY,(CASE WHEN (SELECT SUM(COALESCE(COALESCE(A.n_rwa_ul_amt, A.n_pre_mitigation_rwa_ul), 0)) FROM FSI_CAP_SEC_UNDERLYING A LEFT OUTER JOIN DIM_DATES ON A.n_mis_date_skey = DIM_DATES.n_date_skey WHERE A.N_STD_ACCT_HEAD_SKEY IS NULL AND A.N_RUN_SKEY = E.N_RUN_SKEY AND A.n_mis_date_skey = E.n_mis_date_skey AND A.N_GAAP_SKEY = E.N_GAAP_SKEY AND A.N_SEC_POOL_SKEY = F.N_SEC_POOL_SKEY AND COALESCE(A.F_NETTABILITY_FLAG, 'N') <> 'Y' AND A.N_RUN_SKEY = '870' AND A.n_mis_date_skey = DIM_DATES.n_date_skey GROUP BY A.n_mis_date_skey,A.N_RUN_SKEY,A.N_GAAP_SKEY) > (SELECT SUM(COALESCE(FCT_SEC_EXPOSURES.n_sec_exp_rwa_ul_amt, FCT_SEC_EXPOSURES.n_pre_crm_rwa_ul_amt)) FROM FCT_SEC_EXPOSURES INNER JOIN FCT_SECURITIZATION_TRANCHE ON FCT_SECURITIZATION_TRANCHE.N_RUN_SKEY = FCT_SEC_EXPOSURES.N_RUN_SKEY AND FCT_SEC_EXPOSURES.V_TRANCHE_ID = FCT_SECURITIZATION_TRANCHE.V_TRANCHE_ID AND FCT_SEC_EXPOSURES.n_mis_date_skey = FCT_SECURITIZATION_TRANCHE.n_mis_date_skey LEFT OUTER JOIN DIM_BASEL_METHODOLOGY ON FCT_SEC_EXPOSURES.N_BASEL_METHOD_SKEY = DIM_BASEL_METHODOLOGY.N_BASEL_METHOD_SKEY LEFT OUTER JOIN DIM_DATES ON FCT_SEC_EXPOSURES.n_mis_date_skey = DIM_DATES.n_date_skey WHERE FCT_SEC_EXPOSURES.N_RUN_SKEY = E.N_RUN_SKEY AND FCT_SEC_EXPOSURES.n_mis_date_skey = E.n_mis_date_skey AND FCT_SECURITIZATION_TRANCHE.N_SEC_POOL_SKEY = F.N_SEC_POOL_SKEY AND DIM_BASEL_METHODOLOGY.V_BASEL_RISK_TYPE_ID = 'CR' AND DIM_BASEL_METHODOLOGY.V_BASEL_METHOD_CODE IN ('SECRBA','SECSFA','SECIAA') AND (FCT_SEC_EXPOSURES.N_STD_ACCT_HEAD_SKEY IS NULL OR COALESCE(FCT_SEC_EXPOSURES.N_EAD_BELOW_KIRB, - 1) > 0) /*THIS CONDITION IS APPLICABLE FOR NPR SEC-SFA APPROACH*/ AND FCT_SEC_EXPOSURES.N_RUN_SKEY = '870' AND FCT_SEC_EXPOSURES.n_mis_date_skey = DIM_DATES.n_date_skey GROUP BY FCT_SEC_EXPOSURES.n_mis_date_skey,FCT_SEC_EXPOSURES.N_RUN_SKEY,FCT_SEC_EXPOSURES.N_GAAP_SKEY) THEN (SELECT SUM(COALESCE(FCT_SEC_EXPOSURES.n_sec_exp_rwa_ul_amt, FCT_SEC_EXPOSURES.n_pre_crm_rwa_ul_amt)) FROM FCT_SEC_EXPOSURES INNER JOIN FCT_SECURITIZATION_TRANCHE ON FCT_SECURITIZATION_TRANCHE.N_RUN_SKEY = FCT_SEC_EXPOSURES.N_RUN_SKEY AND FCT_SEC_EXPOSURES.V_TRANCHE_ID = FCT_SECURITIZATION_TRANCHE.V_TRANCHE_ID AND FCT_SEC_EXPOSURES.n_mis_date_skey = FCT_SECURITIZATION_TRANCHE.n_mis_date_skey LEFT OUTER JOIN DIM_BASEL_METHODOLOGY ON FCT_SEC_EXPOSURES.N_BASEL_METHOD_SKEY = DIM_BASEL_METHODOLOGY.N_BASEL_METHOD_SKEY LEFT OUTER JOIN DIM_DATES ON FCT_SEC_EXPOSURES.n_mis_date_skey = DIM_DATES.n_date_skey WHERE FCT_SEC_EXPOSURES.N_RUN_SKEY = E.N_RUN_SKEY AND FCT_SEC_EXPOSURES.n_mis_date_skey = E.n_mis_date_skey AND FCT_SECURITIZATION_TRANCHE.N_SEC_POOL_SKEY = F.N_SEC_POOL_SKEY AND DIM_BASEL_METHODOLOGY.V_BASEL_RISK_TYPE_ID = 'CR' AND DIM_BASEL_METHODOLOGY.V_BASEL_METHOD_CODE IN ( 'SECRBA','SECSFA','SECIAA' ) AND ( FCT_SEC_EXPOSURES.N_STD_ACCT_HEAD_SKEY IS NULL OR COALESCE(FCT_SEC_EXPOSURES.N_EAD_BELOW_KIRB, - 1) > 0 ) /*THIS CONDITION IS APPLICABLE FOR NPR SEC-SFA APPROACH*/ AND FCT_SEC_EXPOSURES.N_RUN_SKEY = '870' AND FCT_SEC_EXPOSURES.n_mis_date_skey = DIM_DATES.n_date_skey GROUP BY FCT_SEC_EXPOSURES.n_mis_date_skey,FCT_SEC_EXPOSURES.N_RUN_SKEY,FCT_SEC_EXPOSURES.N_GAAP_SKEY) ELSE (SELECT SUM(COALESCE(COALESCE(A.n_rwa_ul_amt, A.n_pre_mitigation_rwa_ul), 0)) FROM FSI_CAP_SEC_UNDERLYING A LEFT OUTER JOIN DIM_DATES ON A.n_mis_date_skey = DIM_DATES.n_date_skey WHERE A.N_STD_ACCT_HEAD_SKEY IS NULL AND A.N_RUN_SKEY = E.N_RUN_SKEY AND A.n_mis_date_skey = E.n_mis_date_skey AND A.N_GAAP_SKEY = E.N_GAAP_SKEY AND A.N_SEC_POOL_SKEY = F.N_SEC_POOL_SKEY AND COALESCE(A.F_NETTABILITY_FLAG, 'N') <> 'Y' AND A.N_RUN_SKEY = '870' AND A.n_mis_date_skey = DIM_DATES.n_date_skey GROUP BY A.n_mis_date_skey,A.N_RUN_SKEY,A.N_GAAP_SKEY) END) N_STD_ACCT_HEAD_AMT,(SELECT MAX(N_STD_ACCT_HEAD_SKEY) FROM DIM_STANDARD_ACCT_HEAD A WHERE A.V_STD_ACCT_HEAD_ID = 'CAP218' AND to_date('20260331','YYYYMMDD') BETWEEN A.D_RECORD_START_DATE and A.D_RECORD_END_DATE) N_STD_ACCT_HEAD_SKEY,MAX(E.V_CCY_CODE) V_CCY_CODE,'SEC-EXP' V_RECORD_TYPE,MAX(E.N_BASEL_METHOD_SKEY) N_BASEL_METHOD_SKEY FROM FCT_SEC_EXPOSURES E INNER JOIN DIM_DATES ON E.n_mis_date_skey = DIM_DATES.n_date_skey INNER JOIN (FCT_SECURITIZATION_TRANCHE INNER JOIN FCT_SECURITIZATION_POOL F ON F.N_SEC_POOL_SKEY = FCT_SECURITIZATION_TRANCHE.N_SEC_POOL_SKEY) ON FCT_SECURITIZATION_TRANCHE.N_RUN_SKEY = E.N_RUN_SKEY AND E.V_TRANCHE_ID = FCT_SECURITIZATION_TRANCHE.V_TRANCHE_ID AND E.n_mis_date_skey = FCT_SECURITIZATION_TRANCHE.n_mis_date_skey AND F.N_RUN_SKEY = FCT_SECURITIZATION_TRANCHE.N_RUN_SKEY AND F.n_mis_date_skey = FCT_SECURITIZATION_TRANCHE.n_mis_date_skey LEFT OUTER JOIN DIM_BASEL_METHODOLOGY ON E.N_BASEL_METHOD_SKEY = DIM_BASEL_METHODOLOGY.N_BASEL_METHOD_SKEY WHERE (E.N_STD_ACCT_HEAD_SKEY IS NULL OR COALESCE(E.N_EAD_BELOW_KIRB, - 1) > 0) /*THIS CONDITION IS APPLICABLE FOR NPR SEC-SFA APPROACH*/ AND DIM_BASEL_METHODOLOGY.V_BASEL_RISK_TYPE_ID = 'CR' AND DIM_BASEL_METHODOLOGY.V_BASEL_METHOD_CODE IN ('SECRBA','SECSFA','SECIAA') AND E.N_RUN_SKEY = '870' AND E.n_mis_date_skey = DIM_DATES.n_date_skey GROUP BY E.n_mis_date_skey,E.N_RUN_SKEY,E.N_GAAP_SKEY,F.N_SEC_POOL_SKEY) GROUP BY n_mis_date_skey,N_RUN_SKEY,N_GAAP_SKEY,N_STD_ACCT_HEAD_SKEY,V_RECORD_TYPE HAVING MAX(N_BASEL_METHOD_SKEY) <> 0) SEC_IRB LEFT OUTER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = SEC_IRB.N_RUN_SKEY LEFT OUTER JOIN DIM_DATES ON DIM_DATES.n_date_skey = SEC_IRB.n_mis_date_skey LEFT OUTER JOIN  DIM_CAPITAL_COMP_GROUP ON TO_DATE(to_date('20260331','YYYYMMDD')) BETWEEN COALESCE(DIM_CAPITAL_COMP_GROUP.D_RECORD_START_DATE,TO_DATE(to_date('20260331','YYYYMMDD'))) AND  COALESCE(DIM_CAPITAL_COMP_GROUP.D_RECORD_END_DATE, TO_DATE(to_date('20260331','YYYYMMDD'))) AND DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE = 'OTH' WHERE 1=1 AND DIM_RUN.N_RUN_SKEY = '870' AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') GROUP BY DIM_RUN.N_RUN_SKEY, DIM_DATES.n_date_skey, SEC_IRB.N_GAAP_SKEY, SEC_IRB.N_STD_ACCT_HEAD_SKEY, SEC_IRB.V_RECORD_TYPE,DIM_CAPITAL_COMP_GROUP.N_CAP_COMP_GROUP_SKEY LOG ERRORS INTO FSI_CAP_EXP_STD_ACCT_HEAD$ ('1776770907502_94150003_20260331_1_JOB_6649379887797968') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
